function PrepPage({d,s}){const evN=[...new Set(d.events.map(e=>e.title))];const[selEv,setSelEv]=useState(evN[0]||"");const[txt,setTxt]=useState("");const items=d.checklists.filter(c=>c.event===selEv);const done=items.filter(c=>c.done).length;return(<div className="space-y-4"><Sl value={selEv} onChange={e=>setSelEv(e.target.value)} options={evN}/>{items.length>0&&<div className="bg-gray-200 rounded-full h-2"><div className="bg-orange-500 h-2 rounded-full" style={{width:(done/items.length*100)+"%"}}/></div>}<div className="flex gap-2"><Ip value={txt} onChange={e=>setTxt(e.target.value)} placeholder="Add item..."/><Bt onClick={()=>{if(!txt)return;s({...d,checklists:[...d.checklists,{id:gi(),event:selEv,text:txt,done:false}]});setTxt("")}}><Plus size={16}/></Bt></div>{items.map(c=>(<div key={c.id} className="bg-white rounded-lg p-3 shadow-sm border flex justify-between"><label className="flex items-center gap-2 cursor-pointer"><input type="checkbox" checked={c.done} onChange={()=>s({...d,checklists:d.checklists.map(x=>x.id===c.id?{...x,done:!x.done}:x)})}/><span className={c.done?"line-through text-gray-400":""}>{c.text}</span></label><button onClick={()=>s({...d,checklists:d.checklists.filter(x=>x.id!==c.id)})} className="text-red-400"><Trash2 size={14}/></button></div>))}</div>)}

function PermissionsPage({d,s}){const evN=[...new Set(d.events.map(e=>e.title))];const[selEv,setSelEv]=useState(evN[0]||"");const perms=d.permissions.filter(p=>p.eventTitle===selEv);return(<div className="space-y-4"><div className="flex gap-2"><Sl value={selEv} onChange={e=>setSelEv(e.target.value)} options={evN}/><Bt onClick={()=>{const ex=perms.map(p=>p.studentId);const ms=d.students.filter(st=>!ex.includes(st.id));if(ms.length)s({...d,permissions:[...d.permissions,...ms.map(st=>({id:gi(),eventTitle:selEv,studentId:st.id,slipSigned:false,paid:false}))]})}} v="secondary"><Users size={14}/>Add All</Bt></div><div className="text-sm text-gray-500">{perms.filter(p=>p.slipSigned).length}/{perms.length} slips · {perms.filter(p=>p.paid).length}/{perms.length} paid</div>{perms.map(p=>{const st=d.students.find(x=>x.id===p.studentId);return(<div key={p.id} className="bg-white rounded-xl p-3 shadow-sm border flex justify-between items-center"><span className="font-bold text-sm">{st?st.name:"?"}</span><div className="flex gap-3"><label className="flex items-center gap-1 text-xs"><input type="checkbox" checked={p.slipSigned} onChange={()=>s({...d,permissions:d.permissions.map(x=>x.id===p.id?{...x,slipSigned:!x.slipSigned}:x)})}/>Slip</label><label className="flex items-center gap-1 text-xs"><input type="checkbox" checked={p.paid} onChange={()=>s({...d,permissions:d.permissions.map(x=>x.id===p.id?{...x,paid:!x.paid}:x)})}/>Paid</label><button onClick={()=>s({...d,permissions:d.permissions.filter(x=>x.id!==p.id)})} className="text-red-400"><Trash2 size={12}/></button></div></div>)})}</div>)}

function BudgetPage({d,s}){const[sh,setSh]=useState(false);const[fm,setFm]=useState({description:"",amount:"",category:"Other",date:td(),type:"expense"});const inc=d.budget.filter(b=>b.type==="income").reduce((a,b)=>a+b.amount,0);const exp=d.budget.filter(b=>b.type==="expense").reduce((a,b)=>a+b.amount,0);return(<div className="space-y-4"><div className="grid grid-cols-3 gap-3"><Sc value={"$"+inc.toFixed(2)} label="Income" color="green"/><Sc value={"$"+exp.toFixed(2)} label="Expenses" color="red"/><Sc value={"$"+(inc-exp).toFixed(2)} label="Balance" color={inc>=exp?"green":"red"}/></div><Bt onClick={()=>{setFm({description:"",amount:"",category:"Other",date:td(),type:"expense"});setSh(true)}}><Plus size={16}/></Bt>{d.budget.sort((a,b)=>b.date.localeCompare(a.date)).map(b=>(<div key={b.id} className="bg-white rounded-xl p-3 shadow-sm border flex justify-between items-center"><div><div className="font-bold text-sm">{b.description}</div><div className="text-xs text-gray-500">{b.category} · {fs(b.date)}</div></div><div className="flex items-center gap-2"><span className={"font-bold "+(b.type==="income"?"text-green-600":"text-red-600")}>{b.type==="income"?"+":"-"}${b.amount.toFixed(2)}</span><button onClick={()=>s({...d,budget:d.budget.filter(x=>x.id!==b.id)})} className="text-red-400"><Trash2 size={14}/></button></div></div>))}<M open={sh} onClose={()=>setSh(false)} title="Add"><Fl l="Description"><Ip value={fm.description} onChange={e=>setFm({...fm,description:e.target.value})}/></Fl><Fl l="Amount"><Ip type="number" value={fm.amount} onChange={e=>setFm({...fm,amount:e.target.value})}/></Fl><Fl l="Type"><Sl value={fm.type} onChange={e=>setFm({...fm,type:e.target.value})} options={["income","expense"]}/></Fl><Fl l="Category"><Sl value={fm.category} onChange={e=>setFm({...fm,category:e.target.value})} options={BC}/></Fl><Fl l="Date"><Ip type="date" value={fm.date} onChange={e=>setFm({...fm,date:e.target.value})}/></Fl><Bt onClick={()=>{if(!fm.description||!fm.amount)return;s({...d,budget:[...d.budget,{...fm,id:gi(),amount:parseFloat(fm.amount)}]});setSh(false)}}><Check size={16}/>Save</Bt></M></div>)}

function PackingPage({d,s}){const[sh,setSh]=useState(false);const[fm,setFm]=useState({name:"",event:""});const[txt,setTxt]=useState("");return(<div className="space-y-4"><Bt onClick={()=>{setFm({name:"",event:""});setSh(true)}}><Plus size={16}/>New List</Bt>{d.packingLists.map(pl=>{const done=pl.items.filter(i=>i.packed).length;return(<div key={pl.id} className="bg-white rounded-xl p-4 shadow-sm border"><div className="flex justify-between mb-2"><div className="font-bold">{pl.name}{pl.event&&<span className="text-xs text-gray-500 ml-2">{pl.event}</span>}</div><div className="flex items-center gap-2"><span className="text-xs text-gray-500">{done}/{pl.items.length}</span><button onClick={()=>s({...d,packingLists:d.packingLists.filter(x=>x.id!==pl.id)})} className="text-red-400"><Trash2 size={14}/></button></div></div>{pl.items.length>0&&<div className="bg-gray-200 rounded-full h-1.5 mb-2"><div className="bg-orange-500 h-1.5 rounded-full" style={{width:(done/pl.items.length*100)+"%"}}/></div>}{pl.items.map(i=>(<div key={i.id} className="flex justify-between py-1"><label className="flex items-center gap-2 text-sm cursor-pointer"><input type="checkbox" checked={i.packed} onChange={()=>s({...d,packingLists:d.packingLists.map(l=>l.id===pl.id?{...l,items:l.items.map(x=>x.id===i.id?{...x,packed:!x.packed}:x)}:l)})}/><span className={i.packed?"line-through text-gray-400":""}>{i.text}</span></label><button onClick={()=>s({...d,packingLists:d.packingLists.map(l=>l.id===pl.id?{...l,items:l.items.filter(x=>x.id!==i.id)}:l)})} className="text-red-400"><Trash2 size={12}/></button></div>))}<div className="flex gap-2 mt-2"><Ip value={txt} onChange={e=>setTxt(e.target.value)} placeholder="Add item..."/><Bt onClick={()=>{if(!txt)return;s({...d,packingLists:d.packingLists.map(l=>l.id===pl.id?{...l,items:[...l.items,{id:gi(),text:txt,packed:false}]}:l)});setTxt("")}} v="secondary"><Plus size={14}/></Bt></div></div>)})}<M open={sh} onClose={()=>setSh(false)} title="New List"><Fl l="Name"><Ip value={fm.name} onChange={e=>setFm({...fm,name:e.target.value})}/></Fl><Fl l="Event"><Ip value={fm.event} onChange={e=>setFm({...fm,event:e.target.value})}/></Fl><Bt onClick={()=>{if(!fm.name)return;s({...d,packingLists:[...d.packingLists,{...fm,id:gi(),items:[]}]});setSh(false)}}><Check size={16}/>Create</Bt></M></div>)}

function SocialPage({d,s}){const[sh,setSh]=useState(false);const[fm,setFm]=useState({date:td(),platform:"Instagram",content:"",status:"draft"});return(<div className="space-y-4"><Bt onClick={()=>{setFm({date:td(),platform:"Instagram",content:"",status:"draft"});setSh(true)}}><Plus size={16}/>Add</Bt>{d.socialPosts.sort((a,b)=>a.date.localeCompare(b.date)).map(p=>(<div key={p.id} className="bg-white rounded-xl p-4 shadow-sm border"><div className="flex justify-between items-start"><div><div className="flex gap-2 items-center"><Bg c={p.platform==="Instagram"?"purple":"blue"}>{p.platform}</Bg><Bg c={p.status==="posted"?"green":"gray"}>{p.status}</Bg><span className="text-xs text-gray-500">{fs(p.date)}</span></div><div className="text-sm mt-2">{p.content}</div></div><div className="flex gap-1"><button onClick={()=>s({...d,socialPosts:d.socialPosts.map(x=>x.id===p.id?{...x,status:x.status==="draft"?"posted":"draft"}:x)})} className="p-1 hover:bg-green-50 text-green-600"><Check size={14}/></button><button onClick={()=>s({...d,socialPosts:d.socialPosts.filter(x=>x.id!==p.id)})} className="p-1 hover:bg-red-50 text-red-400"><Trash2 size={14}/></button></div></div></div>))}{!d.socialPosts.length&&<div className="text-center text-gray-400 py-8">No posts</div>}<M open={sh} onClose={()=>setSh(false)} title="Plan Post"><Fl l="Date"><Ip type="date" value={fm.date} onChange={e=>setFm({...fm,date:e.target.value})}/></Fl><Fl l="Platform"><Sl value={fm.platform} onChange={e=>setFm({...fm,platform:e.target.value})} options={PL}/></Fl><Fl l="Content"><Ta value={fm.content} onChange={e=>setFm({...fm,content:e.target.value})}/></Fl><Bt onClick={()=>{if(!fm.content)return;s({...d,socialPosts:[...d.socialPosts,{...fm,id:gi()}]});setSh(false)}}><Check size={16}/>Save</Bt></M></div>)}

function TransportPage({d,s}){const[sh,setSh]=useState(false);const[fm,setFm]=useState({event:"",driver:"",vehicle:"",capacity:"",riders:""});return(<div className="space-y-4"><Bt onClick={()=>{setFm({event:"",driver:"",vehicle:"",capacity:"",riders:""});setSh(true)}}><Plus size={16}/>Add</Bt>{d.transport.map(t=>(<div key={t.id} className="bg-white rounded-xl p-4 shadow-sm border"><div className="flex justify-between"><div><div className="font-bold text-sm">{t.driver}</div><div className="text-xs text-gray-500">{t.vehicle} · Cap: {t.capacity}{t.event?" · "+t.event:""}</div>{t.riders&&<div className="text-xs mt-1">Riders: {t.riders}</div>}</div><button onClick={()=>s({...d,transport:d.transport.filter(x=>x.id!==t.id)})} className="text-red-400"><Trash2 size={14}/></button></div></div>))}{!d.transport.length&&<div className="text-center text-gray-400 py-8">No assignments</div>}<M open={sh} onClose={()=>setSh(false)} title="Add Transport"><Fl l="Event"><Ip value={fm.event} onChange={e=>setFm({...fm,event:e.target.value})}/></Fl><Fl l="Driver"><Ip value={fm.driver} onChange={e=>setFm({...fm,driver:e.target.value})}/></Fl><Fl l="Vehicle"><Ip value={fm.vehicle} onChange={e=>setFm({...fm,vehicle:e.target.value})}/></Fl><Fl l="Capacity"><Ip type="number" value={fm.capacity} onChange={e=>setFm({...fm,capacity:e.target.value})}/></Fl><Fl l="Riders"><Ta value={fm.riders} onChange={e=>setFm({...fm,riders:e.target.value})} placeholder="Names..."/></Fl><Bt onClick={()=>{if(!fm.driver)return;s({...d,transport:[...d.transport,{...fm,id:gi(),capacity:Number(fm.capacity)||0}]});setSh(false)}}><Check size={16}/>Save</Bt></M></div>)}

function StaffPage({d,s}){const[sh,setSh]=useState(false);const[fm,setFm]=useState({name:"",role:"",phone:"",email:"",certs:[],available:true});const tc=(c)=>{const cs=fm.certs.includes(c)?fm.certs.filter(x=>x!==c):[...fm.certs,c];setFm({...fm,certs:cs})};return (<div className="space-y-4"><Bt onClick={()=>{setFm({name:"",role:"",phone:"",email:"",certs:[],available:true});setSh(true)}}><Plus size={16}/>Add Staff</Bt><div className="grid gap-3">{d.staff.map(st=>(<div key={st.id} className="bg-white rounded-xl p-4 shadow-sm border"><div className="flex justify-between items-start"><div className="flex items-center gap-3"><Av name={st.name}/><div><div className="font-bold text-sm">{st.name}</div><div className="text-xs text-gray-500">{st.role}</div><div className="text-xs text-gray-500">{st.phone}{st.email?" · "+st.email:""}</div></div></div><div className="flex items-center gap-2"><Bg c={st.available?"green":"gray"}>{st.available?"Active":"Inactive"}</Bg><button onClick={()=>s({...d,staff:d.staff.filter(x=>x.id!==st.id)})} className="text-red-400"><Trash2 size={14}/></button></div></div>{st.certs.length>0&&<div className="flex gap-1 mt-2 flex-wrap">{st.certs.map(c=>(<Bg key={c} c="blue">{c}</Bg>))}</div>}</div>))}</div>{!d.staff.length&&<div className="text-center text-gray-400 py-8">No staff added</div>}<M open={sh} onClose={()=>setSh(false)} title="Add Staff"><Fl l="Name"><Ip value={fm.name} onChange={e=>setFm({...fm,name:e.target.value})}/></Fl><Fl l="Role"><Ip value={fm.role} onChange={e=>setFm({...fm,role:e.target.value})} placeholder="e.g. Youth Leader, Volunteer"/></Fl><Fl l="Phone"><Ip value={fm.phone} onChange={e=>setFm({...fm,phone:e.target.value})}/></Fl><Fl l="Email"><Ip value={fm.email} onChange={e=>setFm({...fm,email:e.target.value})}/></Fl><Fl l="Certifications"><div className="flex flex-wrap gap-2">{CERTS.map(c=>(<label key={c} className="flex items-center gap-1 text-sm"><input type="checkbox" checked={fm.certs.includes(c)} onChange={()=>tc(c)}/>{c}</label>))}</div></Fl><Bt onClick={()=>{if(!fm.name)return;s({...d,staff:[...d.staff,{...fm,id:gi()}]});setSh(false)}}><Check size={16}/>Save</Bt></M></div>)}

function ReportsPage({d}){const evT=[...new Set(d.events.map(e=>e.title))];const attByEv=evT.map(t=>({title:t,count:d.attendance.filter(a=>a.event===t).reduce((s,a)=>s+a.present.length,0)})).sort((a,b)=>b.count-a.count);const stAtt=d.students.map(st=>({name:st.name,count:d.attendance.filter(a=>a.present.includes(st.id)).length})).sort((a,b)=>b.count-a.count);const mx1=attByEv[0]?.count||1;const mx2=stAtt[0]?.count||1;return(<div className="space-y-6"><div className="grid grid-cols-2 md:grid-cols-4 gap-3"><Sc value={d.students.length} label="Students" color="blue"/><Sc value={d.attendance.reduce((s,a)=>s+a.present.length,0)} label="Check-ins" color="orange"/><Sc value={d.volunteers.length} label="Serving" color="green"/><Sc value={d.milestones.length} label="Milestones" color="purple"/></div><div className="bg-white rounded-xl p-4 shadow-sm border"><h3 className="font-bold mb-3">By Event</h3>{attByEv.map(e=>(<div key={e.title} className="flex items-center gap-3 mb-2"><span className="w-28 text-sm truncate">{e.title}</span><div className="flex-1 bg-gray-200 rounded-full h-3"><div className="bg-orange-500 h-3 rounded-full" style={{width:(e.count/mx1*100)+"%"}}/></div><span className="text-sm font-bold w-8 text-right">{e.count}</span></div>))}</div><div className="bg-white rounded-xl p-4 shadow-sm border"><h3 className="font-bold mb-3">Top Attendees</h3>{stAtt.slice(0,10).map(st=>(<div key={st.name} className="flex items-center gap-3 mb-2"><span className="w-32 text-sm truncate">{st.name}</span><div className="flex-1 bg-gray-200 rounded-full h-3"><div className="bg-blue-500 h-3 rounded-full" style={{width:(st.count/mx2*100)+"%"}}/></div><span className="text-sm font-bold w-8 text-right">{st.count}</span></div>))}</div></div>)}

function MessagesPage({d,s}){const[sh,setSh]=useState(false);const[sel,setSel]=useState(null);const[fm,setFm]=useState({from:"",to:"",subject:"",body:""});const msg=sel?d.messages.find(m=>m.id===sel):null;return(<div className="space-y-4"><Bt onClick={()=>{setFm({from:"",to:"",subject:"",body:""});setSh(true)}}><Plus size={16}/>Compose</Bt>{d.messages.sort((a,b)=>b.date.localeCompare(a.date)).map(m=>(<div key={m.id} onClick={()=>{setSel(m.id);s({...d,messages:d.messages.map(x=>x.id===m.id?{...x,read:true}:x)})}} className={"bg-white rounded-lg p-3 shadow-sm border cursor-pointer hover:shadow-md "+(m.read?"":"border-l-4 border-l-orange-500")}><div className="flex justify-between"><div className={"text-sm "+(m.read?"":"font-bold")}>{m.subject}</div><span className="text-xs text-gray-500">{fs(m.date)}</span></div><div className="text-xs text-gray-500">{m.from} → {m.to}</div></div>))}<M open={!!sel} onClose={()=>setSel(null)} title={msg?.subject||""}>{msg&&<div><div className="text-xs text-gray-500 mb-2">{msg.from} → {msg.to} · {fd(msg.date)}</div><div className="bg-gray-50 p-3 rounded text-sm whitespace-pre-wrap">{msg.body}</div></div>}</M><M open={sh} onClose={()=>setSh(false)} title="Compose"><Fl l="From"><Ip value={fm.from} onChange={e=>setFm({...fm,from:e.target.value})}/></Fl><Fl l="To"><Ip value={fm.to} onChange={e=>setFm({...fm,to:e.target.value})}/></Fl><Fl l="Subject"><Ip value={fm.subject} onChange={e=>setFm({...fm,subject:e.target.value})}/></Fl><Fl l="Message"><Ta value={fm.body} onChange={e=>setFm({...fm,body:e.target.value})}/></Fl><Bt onClick={()=>{if(!fm.subject)return;s({...d,messages:[...d.messages,{...fm,id:gi(),date:td(),read:false}]});setSh(false)}}><Check size={16}/>Send</Bt></M></div>)}

function DataPage({d,s}){const exp=()=>{const blob=new Blob([JSON.stringify(d,null,2)],{type:"application/json"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download="rekindle-"+td()+".json";a.click();URL.revokeObjectURL(url)};return(<div className="space-y-4"><div className="bg-white rounded-xl p-6 shadow-sm border space-y-3"><h3 className="font-bold">Export / Import</h3><div className="flex gap-3"><Bt onClick={exp}><Download size={16}/>Export</Bt><label className="px-4 py-2 rounded-lg text-sm font-medium bg-gray-100 text-gray-700 hover:bg-gray-200 cursor-pointer flex items-center gap-2"><Upload size={16}/>Import<input type="file" accept=".json" onChange={e=>{const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=ev=>{try{s(JSON.parse(ev.target.result))}catch(err){alert("Invalid JSON")}};r.readAsText(f)}} className="hidden"/></label></div></div><div className="bg-white rounded-xl p-6 shadow-sm border"><h3 className="font-bold text-red-600 mb-2">Reset</h3><Bt onClick={()=>{if(confirm("Reset?"))s(JSON.parse(JSON.stringify(DEF)))}} v="danger"><RotateCcw size={16}/>Reset</Bt></div><div className="bg-white rounded-xl p-6 shadow-sm border"><h3 className="font-bold mb-3">Change Log</h3>{d.changeLog.length?<div className="max-h-48 overflow-y-auto space-y-1">{d.changeLog.slice(-20).reverse().map((c,i)=>(<div key={i} className="text-xs flex gap-2 py-1 border-b"><span className="text-gray-400 w-24 shrink-0">{c.date}</span><span className="text-gray-600">{c.action}</span></div>))}</div>:<div className="text-sm text-gray-400">No changes logged yet</div>}</div><div className="bg-white rounded-xl p-6 shadow-sm border"><h3 className="font-bold mb-3">Summary</h3><div className="grid grid-cols-2 md:grid-cols-3 gap-2 text-sm">{[["Students",d.students.length],["Events",d.events.length],["Attendance",d.attendance.length],["Lessons",d.lessons.length],["Follow-ups",d.followups.length],["Prayers",d.prayers.length],["Volunteers",d.volunteers.length],["Budget",d.budget.length],["Social Posts",d.socialPosts.length],["Transport",d.transport.length],["Groups",d.groups.length],["Messages",d.messages.length]].map(([k,v])=>(<div key={k} className="flex justify-between p-2 bg-gray-50 rounded"><span className="text-gray-600">{k}</span><span className="font-bold">{v}</span></div>))}</div></div></div>)}

export default function App(){const[d,setD]=useState(JSON.parse(JSON.stringify(DEF)));const[pg,setPg]=useState("home");const ur=d.messages.filter(m=>!m.read).length;const pf=d.followups.filter(f=>f.status==="pending").length;const nav=[{id:"home",label:"Home",icon:Home},{id:"calendar",label:"Calendar",icon:Calendar},{id:"students",label:"Students",icon:Users},{id:"events",label:"Events",icon:Calendar},{id:"lessons",label:"Lessons",icon:BookOpen},{id:"followup",label:"Follow-Up",icon:Heart,badge:pf},{id:"prayer",label:"Prayer",icon:Star},{id:"serving",label:"Serving",icon:UserCheck},{id:"prep",label:"Prep",icon:ClipboardList},{id:"permissions",label:"Slips & Pay",icon:FileText},{id:"budget",label:"Budget",icon:DollarSign},{id:"packing",label:"Packing",icon:Package},{id:"social",label:"Social",icon:Share2},{id:"transport",label:"Transport",icon:Truck},{id:"staff",label:"Staff",icon:Shield},{id:"reports",label:"Reports",icon:BarChart3},{id:"messages",label:"Messages",icon:MessageSquare,badge:ur},{id:"data",label:"Data",icon:RefreshCw}];return(<div className="flex h-screen bg-gray-50"><div className="w-48 bg-gray-900 text-white flex flex-col shrink-0"><div className="p-3 border-b border-gray-800 flex items-center gap-2"><Flame className="text-orange-500" size={22}/><span className="font-bold">ReKindle</span></div><nav className="flex-1 overflow-y-auto p-2 space-y-0.5">{nav.map(n=>{const Ic=n.icon;return(<button key={n.id} onClick={()=>setPg(n.id)} className={"w-full text-left px-3 py-1.5 rounded-lg text-xs flex items-center gap-2 transition "+(pg===n.id?"bg-orange-500 text-white":"text-gray-300 hover:bg-gray-800")}><Ic size={14}/><span className="flex-1">{n.label}</span>{n.badge>0&&<span className="bg-red-500 text-white text-xs px-1.5 rounded-full">{n.badge}</span>}</button>)})}</nav></div><div className="flex-1 flex flex-col overflow-hidden"><div className="bg-white border-b px-6 py-3 flex items-center justify-between"><h1 className="text-xl font-bold">{nav.find(n=>n.id===pg)?.label}</h1><span className="text-sm text-gray-500">{fd(td())}</span></div><div className="flex-1 overflow-y-auto p-6">{pg==="home"&&<HomePage d={d} s={setD}/>}{pg==="calendar"&&<CalendarPage d={d}/>}{pg==="students"&&<StudentsPage d={d} s={setD}/>}{pg==="events"&&<EventsPage d={d} s={setD}/>}{pg==="lessons"&&<LessonsPage d={d} s={setD}/>}{pg==="followup"&&<FollowUpPage d={d} s={setD}/>}{pg==="prayer"&&<PrayerPage d={d} s={setD}/>}{pg==="serving"&&<ServingPage d={d} s={setD}/>}{pg==="prep"&&<PrepPage d={d} s={setD}/>}{pg==="permissions"&&<PermissionsPage d={d} s={setD}/>}{pg==="budget"&&<BudgetPage d={d} s={setD}/>}{pg==="packing"&&<PackingPage d={d} s={setD}/>}{pg==="social"&&<SocialPage d={d} s={setD}/>}{pg==="transport"&&<TransportPage d={d} s={setD}/>}{pg==="staff"&&<StaffPage d={d} s={setD}/>}{pg==="reports"&&<ReportsPage d={d}/>}{pg==="messages"&&<MessagesPage d={d} s={setD}/>}{pg==="data"&&<DataPage d={d} s={setD}/>}</div></div></div>)}